#!/usr/bin/env python3
import sys
import xml.etree.ElementTree as ET


def service_names(path: str) -> list[str]:
    root = ET.parse(path).getroot()
    return [node.get('name', '') for node in root.findall('.//service')]


if __name__ == '__main__':
    for name in service_names(sys.argv[1]):
        print(name)
